INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES
(gen_random_uuid(), 'sl', 97, 1, NULL, 'William Perkins em Sl 97:1', 'Na leitura de William Perkins, vemos a piedade prática e a santificação do coração. Salmos 97 evidencia adoração, sabedoria e temor do Senhor como eixo da vida do povo de Deus, com ênfase em esperança escatológica. A passagem confronta o coração e organiza a prática diária do discípulo. Aplicação: submeta sua vontade à Palavra e caminhe em fidelidade.', 'William Perkins', 'commentary', '#2E8B57', NOW()),
(gen_random_uuid(), 'sl', 98, 1, NULL, 'B. B. Warfield em Sl 98:1', 'Segundo B. B. Warfield, a coerência doutrinária aplicada à vida cristã ilumina o sentido deste texto. Salmos 98 mostra que adoração, sabedoria e temor do Senhor sustenta a caminhada da fé, especialmente em obediência da fé. A doutrina aqui conduz à devoção e à perseverança. Aplicação: firme-se nas promessas divinas e pratique a verdade com humildade.', 'B. B. Warfield', 'commentary', '#1D4ED8', NOW()),
(gen_random_uuid(), 'sl', 99, 1, NULL, 'Tomás de Aquino em Sl 99:1', 'Tomás de Aquino destaca a síntese entre fé, razão e vida santa. Em Salmos 99, o foco recai sobre adoração, sabedoria e temor do Senhor e chama a igreja para justiça com misericórdia. O texto orienta a fé para uma obediência concreta e perseverante. Aplicação: receba esta verdade com fé, arrependimento e esperança ativa.', 'Tomás de Aquino', 'commentary', '#6B4F2A', NOW()),
(gen_random_uuid(), 'sl', 100, 1, NULL, 'Thomas Goodwin em Sl 100:1', 'Thomas Goodwin interpreta este versículo a partir de a piedade prática e a santificação do coração. Em Salmos 100, Deus revela adoração, sabedoria e temor do Senhor de forma pastoral e transformadora, promovendo perseverança na tribulação. A verdade bíblica forma caráter, culto e missão. Aplicação: responda com oração, disciplina espiritual e serviço cristão.', 'Thomas Goodwin', 'commentary', '#2E8B57', NOW()),
(gen_random_uuid(), 'sl', 101, 1, NULL, 'Alexander Maclaren em Sl 101:1', 'Alexander Maclaren destaca a coerência doutrinária aplicada à vida cristã. Em Salmos 101, o foco recai sobre adoração, sabedoria e temor do Senhor e chama a igreja para fidelidade na aliança. O texto orienta a fé para uma obediência concreta e perseverante. Aplicação: receba esta verdade com fé, arrependimento e esperança ativa.', 'Alexander Maclaren', 'commentary', '#1D4ED8', NOW()),
(gen_random_uuid(), 'sl', 102, 1, NULL, 'Basílio de Cesareia em Sl 102:1', 'Na leitura de Basílio de Cesareia, vemos a leitura cristológica e eclesial da passagem. Salmos 102 evidencia adoração, sabedoria e temor do Senhor como eixo da vida do povo de Deus, com ênfase em arrependimento sincero. A passagem confronta o coração e organiza a prática diária do discípulo. Aplicação: submeta sua vontade à Palavra e caminhe em fidelidade.', 'Basílio de Cesareia', 'commentary', '#8B4513', NOW()),
